     5→//! Notch command - JJ-aware commit with heat/pace context prefix
     6→//!
     7→//! This module handles the jjx_notch command which performs a staged commit
     8→//! with heat/pace context prefix. It accepts explicit file list and generates
     9→//! a JJ context-aware commit message.
    10→
    11→use clap::Args;
    12→use std::collections::HashSet;
    13→use std::process::Command;
    14→
    15→use crate::jjrf_favor::{jjrf_Coronet as Coronet, jjrf_Firemark as Firemark, JJRF_FIREMARK_PREFIX, JJRF_CORONET_PREFIX};
    16→use crate::jjrn_notch::jjrn_format_notch_prefix;
    17→
    18→/// Arguments for jjx_notch command
    19→#[derive(Args, Debug)]
    20→pub struct jjrnc_NotchArgs {
    21→    /// Identity: Coronet (5-char, pace-affiliated) or Firemark (2-char, heat-only)
    22→    pub identity: String,
    23→
    24→    /// Files to commit (required, at least one)
    25→    #[arg(required = true)]
    26→    pub files: Vec<String>,
    27→
    28→    /// Size limit in bytes (overrides default 50KB guard)
    29→    #[arg(long)]
    30→    pub size_limit: Option<u64>,
    31→
    32→    /// User-provided commit message intent (overrides haiku-generated message)
    33→    #[arg(long)]
    34→    pub intent: Option<String>,
    35→}
    36→
    37→/// Run the notch command
    38→///
    39→/// Stages specified files and commits with JJ-aware prefix.
    40→/// Supports both pace-affiliated (Coronet) and heat-only (Firemark) commits.
    41→pub fn jjrnc_run_notch(args: jjrnc_NotchArgs) -> i32 {
    42→    // Require non-empty files list
    43→    if args.files.is_empty() {
    44→        eprintln!("jjx_notch: error: at least one file required");
    45→        return 1;
    46→    }
    47→
    48→    // Check each file exists
    49→    for file in &args.files {
    50→        if !std::path::Path::new(file).exists() {
    51→            eprintln!("jjx_notch: error: file does not exist: {}", file);
    52→            return 1;
    53→        }
    54→    }
    55→
    56→    // Parse identity - support both Coronet (5 chars) and Firemark (2 chars)
    57→    let identity = args.identity.strip_prefix(JJRF_CORONET_PREFIX).or_else(|| args.identity.strip_prefix(JJRF_FIREMARK_PREFIX)).unwrap_or(&args.identity);
    58→
    59→    let message = if identity.len() == 5 {
    60→        // Coronet - pace-affiliated commit
    61→        let coronet = match Coronet::jjrf_parse(&args.identity) {
    62→            Ok(c) => c,
    63→            Err(e) => {
    64→                eprintln!("jjx_notch: error: {}", e);
    65→                return 1;
    66→            }
    67→        };
    68→        jjrn_format_notch_prefix(&coronet)
    69→    } else if identity.len() == 2 {
    70→        // Firemark - heat-only commit (build format manually to avoid calling private function)
    71→        let firemark = match Firemark::jjrf_parse(&args.identity) {
    72→            Ok(fm) => fm,
    73→            Err(e) => {
    74→                eprintln!("jjx_notch: error: {}", e);
    75→                return 1;
    76→            }
    77→        };
    78→        // Read hallmark from git config jj.hallmark (same as zjjrn_get_hallmark)
    79→        let hallmark_output = match Command::new("git")
    80→            .args(["config", "jj.hallmark"])
    81→            .output()
    82→        {
    83→            Ok(o) => o,
    84→            Err(e) => {
    85→                eprintln!("jjx_notch: error: failed to read jj.hallmark: {}", e);
    86→                return 1;
    87→            }
    88→        };
    89→        let hallmark = if hallmark_output.status.success() {
    90→            String::from_utf8_lossy(&hallmark_output.stdout).trim().to_string()
    91→        } else {
    92→            "1010".to_string()
    93→        };
    94→        // Format: jjb:HALLMARK:₣FIREMARK:n:
    95→        format!(
    96→            "jjb:{}:{}{}:n: ",
    97→            hallmark,
    98→            JJRF_FIREMARK_PREFIX,
    99→            firemark.jjrf_as_str(),
   100→        )
   101→    } else {
   102→        eprintln!("jjx_notch: error: identity must be Coronet (5 chars) or Firemark (2 chars), got {} chars", identity.len());
   103→        return 1;
   104→    };
   105→
   106→    // Warn about uncommitted changes outside the file list
   107→    let output = match Command::new("git")
   108→        .args(["status", "--porcelain"])
   109→        .output()
   110→    {
   111→        Ok(o) => o,
   112→        Err(e) => {
   113→            eprintln!("jjx_notch: error: failed to run git status: {}", e);
   114→            return 1;
   115→        }
   116→    };
   117→
   118→    if !output.status.success() {
   119→        eprintln!("jjx_notch: error: git status failed");
   120→        return 1;
   121→    }
   122→
   123→    let status_output = String::from_utf8_lossy(&output.stdout);
   124→    let files_set: HashSet<_> = args.files.iter().map(|s| s.as_str()).collect();
   125→    let mut warnings = Vec::new();
   126→
   127→    for line in status_output.lines() {
   128→        if line.len() < 4 {
   129→            continue;
   130→        }
   131→        // Parse git status --porcelain format: "XY filename"
   132→        let filepath = &line[3..];
   133→        if !files_set.contains(filepath) {
   134→            warnings.push(format!("  {}", line));
   135→        }
   136→    }
   137→
   138→    if !warnings.is_empty() {
   139→        eprintln!("warning: uncommitted changes outside file list:");
   140→        for warning in warnings {
   141→            eprintln!("{}", warning);
   142→        }
   143→    }
   144→
   145→    // Stage only the specified files
   146→    let mut git_add = Command::new("git");
   147→    git_add.arg("add");
   148→    for file in &args.files {
   149→        git_add.arg(file);
   150→    }
   151→
   152→    let add_output = match git_add.output() {
   153→        Ok(o) => o,
   154→        Err(e) => {
   155→            eprintln!("jjx_notch: error: failed to run git add: {}", e);
   156→            return 1;
   157→        }
   158→    };
   159→
   160→    if !add_output.status.success() {
   161→        eprintln!("jjx_notch: error: git add failed");
   162→        return 1;
   163→    }
   164→
   165→    // Commit using vvc with the generated message prefix
   166→    // If --intent provided, use it as the message; otherwise let haiku generate it
   167→    let commit_args = if let Some(intent) = args.intent {
   168→        vvc::vvcc_CommitArgs {
   169→            prefix: None,
   170→            message: Some(format!("{}{}", message, intent)),
   171→            allow_empty: false,
   172→            no_stage: true,  // We already staged above
   173→            size_limit: args.size_limit.unwrap_or(vvc::VVCG_SIZE_LIMIT),
   174→            warn_limit: vvc::VVCG_WARN_LIMIT,
   175→        }
   176→    } else {
   177→        vvc::vvcc_CommitArgs {
   178→            prefix: Some(message),
   179→            message: None,
   180→            allow_empty: false,
   181→            no_stage: true,  // We already staged above
   182→            size_limit: args.size_limit.unwrap_or(vvc::VVCG_SIZE_LIMIT),
   183→            warn_limit: vvc::VVCG_WARN_LIMIT,
   184→        }
   185→    };
   186→
   187→    vvc::commit(&commit_args)
   188→}
